import type * as DMMF from '@prisma/dmmf'

/** Maps Prisma scalar type names to their TypeScript equivalents. */
const SCALAR_TYPE_MAP: Readonly<Record<string, string>> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  BigInt: 'bigint',
  Float: 'number',
  Decimal: 'number',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Uint8Array',
}

/**
 * Returns the TypeScript base type string for a DMMF field, without list or
 * nullability wrappers.
 */
export function mapScalarType(field: DMMF.Field): string {
  if (field.kind === 'enum') return field.type
  if (field.kind === 'object') return field.type
  if (field.kind === 'unsupported') return 'unknown'
  return SCALAR_TYPE_MAP[field.type] ?? 'unknown'
}

/**
 * Returns the full TypeScript type annotation for a field — base type wrapped
 * with `[]` when it is a list, then optionally followed by `| null`.
 */
export function buildTsType(field: DMMF.Field, opts: { nullable?: boolean } = {}): string {
  const base = mapScalarType(field)
  const withList = field.isList ? `${base}[]` : base
  const nullable = opts.nullable ?? !field.isRequired
  return nullable ? `${withList} | null` : withList
}

