/** Returns the source code for the shared base HTTP client written to `base-client.ts`. */
export function generateBaseClient(): string {
  return `/**
 * Base HTTP client shared by all model REST clients.
 */
export class RestBaseClient {
  constructor(
    protected readonly baseUrl: string,
    protected readonly defaultInit?: Omit<RequestInit, 'body' | 'method'>,
  ) {}

  protected async request<T>(path: string, init?: RequestInit): Promise<T> {
    const url = \`\${this.baseUrl}\${path}\`
    const merged: RequestInit = {
      ...this.defaultInit,
      ...init,
      headers: {
        'Content-Type': 'application/json',
        ...this.defaultInit?.headers,
        ...init?.headers,
      },
    }
    const response = await fetch(url, merged)
    if (!response.ok) {
      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }
}
`
}

