  lines.push(`    if (args?.orderBy !== undefined) params.set('orderBy', JSON.stringify(args.orderBy))`)
  lines.push(`    if (args?.skip !== undefined) params.set('skip', String(args.skip))`)
  lines.push(`    if (args?.take !== undefined) params.set('take', String(args.take))`)
  lines.push(`    const qs = params.size > 0 ? \`?\${params}\` : ''`)
  lines.push(`    return this.request<${n}[]>(\`${path}\${qs}\`)`)
  lines.push(`  }`)
  lines.push(``)

  // findUnique
  lines.push(`  async findUnique(args: ${n}FindUniqueArgs): Promise<${n} | null> {`)
  lines.push(`    const params = new URLSearchParams({ where: JSON.stringify(args.where) })`)
  lines.push(`    return this.request<${n} | null>(\`${path}/findUnique?\${params}\`)`)
  lines.push(`  }`)
  lines.push(``)

