  lines.push(`  async create(args: ${n}CreateArgs): Promise<${n}> {`)
  lines.push(`    return this.request<${n}>('${path}', {`)
  lines.push(`      method: 'POST',`)
  lines.push(`      body: JSON.stringify(args.data),`)
  lines.push(`    })`)
  lines.push(`  }`)
  lines.push(``)

  // update
  lines.push(`  async update(args: ${n}UpdateArgs): Promise<${n}> {`)
  lines.push(`    return this.request<${n}>('${path}', {`)
  lines.push(`      method: 'PUT',`)
  lines.push(`      body: JSON.stringify(args),`)
  lines.push(`    })`)
  lines.push(`  }`)
  lines.push(``)

  // delete
  lines.push(`  async delete(args: ${n}DeleteArgs): Promise<${n}> {`)
  lines.push(`    return this.request<${n}>('${path}', {`)
  lines.push(`      method: 'DELETE',`)
  lines.push(`      body: JSON.stringify(args.where),`)
  lines.push(`    })`)
  lines.push(`  }`)

  lines.push(`}`)
  lines.push(``)

  return lines.join('\n')
}

