import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { version } from '../package.json'
import { generateRestClient } from './generate-client'

const OUTPUT_REQUIRED_MESSAGE = `An output path is required for the \`prisma-rest-client\` generator.
Add an output path to your Prisma config:

  generator restClient {
    provider = "prisma-rest-client"
    output   = "../src/generated/rest-client"
  }
`

function resolveOutputDir(config: GeneratorConfig): string {
  if (!config.output) {
    throw new Error(OUTPUT_REQUIRED_MESSAGE)
  }
  return parseEnvValue(config.output)
}

/**
 * Prisma generator that produces a typed TypeScript REST API client from a
 * Prisma schema.  For each model it emits a TypeScript interface and a class
 * with `findMany`, `findUnique`, `create`, `update`, and `delete` methods that
 * call a REST server using the browser-native `fetch` API.
 *
 * Register it in `prisma.config.ts` (or the legacy `schema.prisma`) with:
 *
 * ```prisma
 * generator restClient {
 *   provider = "prisma-rest-client"
 *   output   = "../src/generated/rest-client"
 * }
 * ```
 */
export class RestClientGenerator implements Generator {
  readonly name = 'prisma-rest-client'

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client',
      defaultOutput: 'generated/rest-client',
      version,
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = resolveOutputDir(options.generator)
    await generateRestClient({ dmmf: options.dmmf, outputDir })
  }
}

