import type * as DMMF from '@prisma/dmmf'
import pluralize from 'pluralize'

import { buildTsType, mapScalarType } from './map-field-type'

/** Returns a lowercase-first camelCase version of a PascalCase name. */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Returns the URL path segment for a model (e.g. `User` → `/users`). */
function resourcePath(modelName: string): string {
  return `/${pluralize(lcFirst(modelName))}`
}

/** Fields that can appear in write (create/update) operations. */
function writableFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter(
    (f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isReadOnly && !f.isUpdatedAt,
  )
}

/** Scalar and enum fields usable in filter/orderBy positions. */
function filterableFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/** Fields that uniquely identify a record (id or unique scalar/enum fields). */
function uniqueKeyFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter(
    (f) => (f.isId || f.isUnique) && (f.kind === 'scalar' || f.kind === 'enum'),
  )
}

/** True when a writable field may be omitted from a `create` call. */
function isOptionalInCreate(field: DMMF.Field): boolean {
  return !field.isRequired || field.hasDefaultValue || field.isId === true
}

/**
 * Generates the full TypeScript source for the per-model file that contains
 * the model interface, all arg interfaces, and the typed REST client class.
 */
export function generateModelFile(model: DMMF.Model): string {
  const path = resourcePath(model.name)
  const n = model.name
  const lines: string[] = []

  lines.push(`import { RestBaseClient } from '../base-client'`)
  lines.push(``)

  // ── Model interface ────────────────────────────────────────────────────────

  lines.push(`export interface ${n} {`)
  for (const field of model.fields) {
    if (field.kind === 'unsupported') continue

    if (field.kind === 'object') {
      // Relation fields: always optional because they are not fetched by default.
      const type = field.isList ? `${field.type}[]` : `${field.type} | null`
      lines.push(`  ${field.name}?: ${type}`)
    } else {
      const type = buildTsType(field)
      const modifier = field.isRequired ? '' : '?'
      lines.push(`  ${field.name}${modifier}: ${type}`)
    }
  }
  lines.push(`}`)
  lines.push(``)

  // ── WhereInput ─────────────────────────────────────────────────────────────

  lines.push(`export interface ${n}WhereInput {`)
  for (const field of filterableFields(model)) {
    const type = buildTsType(field)
    lines.push(`  ${field.name}?: ${type}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── WhereUniqueInput ───────────────────────────────────────────────────────

  lines.push(`export interface ${n}WhereUniqueInput {`)
  for (const field of uniqueKeyFields(model)) {
    // Unique/id fields are never nullable.
    const type = mapScalarType(field)
    lines.push(`  ${field.name}?: ${type}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── CreateInput ────────────────────────────────────────────────────────────

  lines.push(`export interface ${n}CreateInput {`)
  for (const field of writableFields(model)) {
    const type = buildTsType(field)
    const modifier = isOptionalInCreate(field) ? '?' : ''
    lines.push(`  ${field.name}${modifier}: ${type}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── UpdateInput ────────────────────────────────────────────────────────────

  lines.push(`export interface ${n}UpdateInput {`)
  for (const field of writableFields(model)) {
    const type = buildTsType(field)
    lines.push(`  ${field.name}?: ${type}`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── OrderByInput ───────────────────────────────────────────────────────────

  lines.push(`export interface ${n}OrderByInput {`)
  for (const field of filterableFields(model)) {
    lines.push(`  ${field.name}?: 'asc' | 'desc'`)
  }
  lines.push(`}`)
  lines.push(``)

  // ── Operation arg interfaces ───────────────────────────────────────────────

  lines.push(`export interface ${n}FindManyArgs {`)
  lines.push(`  where?: ${n}WhereInput`)
  lines.push(`  orderBy?: ${n}OrderByInput`)
  lines.push(`  skip?: number`)
  lines.push(`  take?: number`)
  lines.push(`}`)
  lines.push(``)

  lines.push(`export interface ${n}FindUniqueArgs {`)
  lines.push(`  where: ${n}WhereUniqueInput`)
  lines.push(`}`)
  lines.push(``)

  lines.push(`export interface ${n}CreateArgs {`)
  lines.push(`  data: ${n}CreateInput`)
  lines.push(`}`)
  lines.push(``)

  lines.push(`export interface ${n}UpdateArgs {`)
  lines.push(`  where: ${n}WhereUniqueInput`)
  lines.push(`  data: ${n}UpdateInput`)
  lines.push(`}`)
  lines.push(``)

  lines.push(`export interface ${n}DeleteArgs {`)
  lines.push(`  where: ${n}WhereUniqueInput`)
  lines.push(`}`)
  lines.push(``)

  // ── REST client class ──────────────────────────────────────────────────────

  lines.push(`/**`)
  lines.push(` * REST API client for the \`${n}\` model.`)
  lines.push(` *`)
  lines.push(` * Assumes a server that follows the routing convention generated by this`)
  lines.push(` * package: every route is prefixed with \`${path}\`.`)
  lines.push(` */`)
  lines.push(`export class ${n}RestClient extends RestBaseClient {`)

  // findMany
  lines.push(`  async findMany(args?: ${n}FindManyArgs): Promise<${n}[]> {`)
  lines.push(`    const params = new URLSearchParams()`)
  lines.push(`    if (args?.where !== undefined) params.set('where', JSON.stringify(args.where))`)
  lines.push(`    if (args?.orderBy !== undefined) params.set('orderBy', JSON.stringify(args.orderBy))`)
  lines.push(`    if (args?.skip !== undefined) params.set('skip', String(args.skip))`)
  lines.push(`    if (args?.take !== undefined) params.set('take', String(args.take))`)
  lines.push(`    const qs = params.size > 0 ? \`?\${params}\` : ''`)
  lines.push(`    return this.request<${n}[]>(\`${path}\${qs}\`)`)
  lines.push(`  }`)
  lines.push(``)

  // findUnique
  lines.push(`  async findUnique(args: ${n}FindUniqueArgs): Promise<${n} | null> {`)
  lines.push(`    const params = new URLSearchParams({ where: JSON.stringify(args.where) })`)
  lines.push(`    return this.request<${n} | null>(\`${path}/findUnique?\${params}\`)`)
  lines.push(`  }`)
  lines.push(``)

  // create
  lines.push(`  async create(args: ${n}CreateArgs): Promise<${n}> {`)
  lines.push(`    return this.request<${n}>('${path}', {`)
  lines.push(`      method: 'POST',`)
  lines.push(`      body: JSON.stringify(args.data),`)
  lines.push(`    })`)
  lines.push(`  }`)
  lines.push(``)

  // update
  lines.push(`  async update(args: ${n}UpdateArgs): Promise<${n}> {`)
  lines.push(`    return this.request<${n}>('${path}', {`)
  lines.push(`      method: 'PUT',`)
  lines.push(`      body: JSON.stringify(args),`)
  lines.push(`    })`)
  lines.push(`  }`)
  lines.push(``)

  // delete
  lines.push(`  async delete(args: ${n}DeleteArgs): Promise<${n}> {`)
  lines.push(`    return this.request<${n}>('${path}', {`)
  lines.push(`      method: 'DELETE',`)
  lines.push(`      body: JSON.stringify(args.where),`)
  lines.push(`    })`)
  lines.push(`  }`)

  lines.push(`}`)
  lines.push(``)

  return lines.join('\n')
}
